Timer timer;
int counter = 0;

public FormMain()
{
    InitializeComponent();
    timer = new Timer();
    timer.Interval = 1000; // 1 секунда
    timer.Tick += Timer_Tick;
    timer.Start();
}

private void Timer_Tick(object sender, EventArgs e)
{
    counter++;
    labelTimer.Text = $"Прошло секунд: {counter}";
    if (counter >= 10)
    {
        timer.Stop();
        MessageBox.Show("10 секунд прошло!");
    }
}

public FormMain()
{
    InitializeComponent();
    this.KeyPreview = true;
    this.KeyDown += FormMain_KeyDown;
}

private void FormMain_KeyDown(object sender, KeyEventArgs e)
{
    labelInfo.Text = $"Нажата клавиша: {e.KeyCode}";
}

private void FormMain_KeyDown(object sender, KeyEventArgs e)
{
    if (e.KeyCode == Keys.D)
    {
        MessageBox.Show("Вы нажали D!");
    }
}

private void FormMain_KeyDown(object sender, KeyEventArgs e)
{
    if (e.Shift && e.KeyCode == Keys.D)
        labelMain.Text = "Вы нажали Shift + D";
    else if (e.Control && e.KeyCode == Keys.D)
        labelMain.Text = "Вы нажали Ctrl + D";
    else if (e.Alt && e.KeyCode == Keys.D)
        labelMain.Text = "Вы нажали Alt + D";
    else if (e.Shift && e.Control && e.KeyCode == Keys.F)
        labelMain.Text = "Вы нажали Shift + Ctrl + F";
}

